const assets = {
  "html": "",
  "css": "",
  "js": ""
};

const routes = {
  "/": { key: "html", type: "text/html; charset=utf-8" },
  "/index.html": { key: "html", type: "text/html; charset=utf-8" },
  "/assets/styles.css": { key: "css", type: "text/css; charset=utf-8" },
  "/assets/app.js": { key: "js", type: "text/javascript; charset=utf-8" }
};

function send(res, route) {
  const body = Buffer.from(assets[route.key], "base64");
  res.statusCode = 200;
  res.setHeader("content-type", route.type);
  res.setHeader("cache-control", "public, max-age=0, must-revalidate");
  res.end(body);
}

module.exports = (req, res) => {
  const url = new URL(req.url || "/", "https://bank-statement-itr-analyzer.vercel.app");
  const route = routes[url.pathname] || routes["/"];
  send(res, route);
};
